func:
msg.headers = {
    "Content-Type": "application/json"
};

msg.payload = {
    grant_type: "client_credentials",
    client_id: env.get("OAUTH_CLIENT_ID") || "gateway",
    client_secret: env.get("OAUTH_CLIENT_SECRET") || "GatewaySecretDev123"
};

return msg;

if (msg.statusCode === 200 && msg.payload && msg.payload.access_token) {
    global.set("authToken", msg.payload.access_token);
    node.status({ fill: "green", shape: "dot", text: "token ready" });
} else {
    node.warn("OAuth bootstrap gagal: " + JSON.stringify(msg.payload));
    node.status({ fill: "red", shape: "ring", text: "token error" });
}

return null;

const topic = msg.topic || "";
const data = msg.payload || {};

if (topic.endsWith("/sungai")) {
    context.set("sungai", data);
} else if (topic.endsWith("/cuaca")) {
    context.set("cuaca", data);
} else {
    return null;
}

const sungai = context.get("sungai");
const cuaca = context.get("cuaca");

if (!sungai || !cuaca) {
    node.status({ fill: "yellow", shape: "ring", text: "waiting pair" });
    return null;
}

const merged = Object.assign({}, sungai, cuaca, {
    idNode: sungai.idNode || cuaca.idNode || 1
});

context.set("sungai", null);
context.set("cuaca", null);
node.status({ fill: "green", shape: "dot", text: "merged" });

msg.payload = merged;
msg.iotBody = merged;
return msg;

const queue = global.get("iotPendingQueue") || [];

if (!queue.length) {
  node.status({ fill: "grey", shape: "ring", text: "queue empty" });
  return null;
}

const next = queue.shift();
global.set("iotPendingQueue", queue);

msg.payload = next;
msg.iotBody = next;
msg.topic = "queue/retry";
node.status({ fill: "blue", shape: "dot", text: queue.length + " left" });
return msg;

const body = msg.iotBody || msg.payload;
if (!body || typeof body !== "object") {
    return null;
}

msg.iotBody = body;
msg.payload = body;

const token = global.get("authToken");
if (!token) {
    const queue = global.get("iotPendingQueue") || [];
    const exists = queue.some((item) => JSON.stringify(item) === JSON.stringify(body));
    if (!exists) {
        if (queue.length >= 50) {
            queue.shift();
        }
        queue.push(body);
        global.set("iotPendingQueue", queue);
    }
    node.warn("Token belum tersedia — payload masuk antrian (" + queue.length + ")");
    node.status({ fill: "yellow", shape: "ring", text: "queued " + queue.length });
    return null;
}

msg.headers = {
    "Content-Type": "application/json",
    "Authorization": "Bearer " + token
};

node.status({ fill: "green", shape: "dot", text: "auth ok" });
return msg;

const code = msg.statusCode || 0;
const body = msg.iotBody;

if (code >= 200 && code < 300) {
    node.status({ fill: "green", shape: "dot", text: "posted " + code });
    return msg;
}

if (!body) {
    node.warn("Gateway error tanpa iotBody: " + code);
    return null;
}

const queue = global.get("iotPendingQueue") || [];
const exists = queue.some((item) => JSON.stringify(item) === JSON.stringify(body));
if (!exists) {
    if (queue.length >= 50) {
        queue.shift();
    }
    queue.push(body);
    global.set("iotPendingQueue", queue);
}

node.warn("Gateway HTTP " + code + " — antrian " + queue.length);
node.status({ fill: "red", shape: "ring", text: "queued " + queue.length });
return null;

const body = msg.iotBody;
if (!body) {
    node.warn("HTTP error tanpa iotBody: " + (msg.error || msg.payload));
    return null;
}

const queue = global.get("iotPendingQueue") || [];
const exists = queue.some((item) => JSON.stringify(item) === JSON.stringify(body));
if (!exists) {
    if (queue.length >= 50) {
        queue.shift();
    }
    queue.push(body);
    global.set("iotPendingQueue", queue);
}

node.warn("Gateway unreachable — antrian " + queue.length + ": " + (msg.error || ""));
node.status({ fill: "red", shape: "ring", text: "queued " + queue.length });
return null;
